import React from "react";
import { Card, CardContent, Typography, Button, Table, TableHead, TableRow, TableCell, TableBody } from "@mui/material";
import { Link } from "react-router-dom";

const HealthInsuranceList = () => {
    const dummyData = [
        { id: 1, name: "Nguyễn Văn A", bhytCode: "BHYT123456", status: "Còn hiệu lực" },
        { id: 2, name: "Trần Thị B", bhytCode: "BHYT789012", status: "Hết hạn" },
    ];

    return (
        <Card>
            <CardContent>
                <Typography variant="h5">Danh sách Bảo Hiểm Y Tế</Typography>
                <Button variant="contained" color="primary" component={Link} to="/admin/add-bhyt" style={{ margin: "10px 0" }}>
                    Thêm BHYT
                </Button>
                <Table>
                    <TableHead>
                        <TableRow>
                            <TableCell>STT</TableCell>
                            <TableCell>Họ Tên</TableCell>
                            <TableCell>Mã BHYT</TableCell>
                            <TableCell>Trạng Thái</TableCell>
                        </TableRow>
                    </TableHead>
                    <TableBody>
                        {dummyData.map((item, index) => (
                            <TableRow key={item.id}>
                                <TableCell>{index + 1}</TableCell>
                                <TableCell>{item.name}</TableCell>
                                <TableCell>{item.bhytCode}</TableCell>
                                <TableCell>{item.status}</TableCell>
                            </TableRow>
                        ))}
                    </TableBody>
                </Table>
            </CardContent>
        </Card>
    );
};

export default HealthInsuranceList;
